+    #[test]
+    fn tracker_last_activity_is_after_epoch() {
+        let t = ActivityTracker::new();
+        let epoch = t.epoch;
+        t.record();
+        let last = t.last_activity().unwrap();
+        assert!(last >= epoch, "last_activity should be >= epoch");
+    }
